def feature_block_ids() -> list[int]:
    return [BLOCK_NAME_TO_ID[f["block"]] for f in FEATURES]


def feature_direction_ids() -> list[int]:
    return [DIRECTION_VOCAB[f["direction"]] for f in FEATURES]


def build_feature_manifest() -> dict:
    return {
        "manifest_version": SCHEMA_VERSION,
        "n_continuous_features": len(CONTINUOUS_COLUMNS),
        "n_categorical_fields": len(CATEGORICAL_COLUMNS),
        "n_acd_targets": len(ACD_TARGET_COLUMNS),
        "blocks": BLOCKS,
        "direction_vocab": DIRECTION_VOCAB,
        "features": FEATURES,
        "categorical_fields": CATEGORICAL_FIELDS,
    }


def validate_manifest(manifest: dict) -> None:
    if manifest.get("manifest_version") != SCHEMA_VERSION:
        raise ValueError(f"schema_version must be {SCHEMA_VERSION}, got {manifest.get('manifest_version')}")
    feats = manifest.get("features") or []
    if len(feats) != 129:
        raise ValueError(f"AVS256 manifest must contain exactly 129 features, got {len(feats)}")
    names = [f.get("name") for f in feats]
    if names != CONTINUOUS_COLUMNS:
        raise ValueError("AVS256 manifest feature order/name mismatch against binding contract")
    if int(manifest.get("n_acd_targets", -1)) != 118:
        raise ValueError(f"n_acd_targets must be 118, got {manifest.get('n_acd_targets')}")
    if int(manifest.get("n_categorical_fields", -1)) != 2:
        raise ValueError(f"n_categorical_fields must be 2, got {manifest.get('n_categorical_fields')}")
